BFS исследует граф «слоями» через очередь: сначала соседи стартовой вершины, потом соседи соседей. Находит кратчайший путь по числу рёбер в невзвешенном графе.

**💡**** Шпаргалка: **BFS опирается на очередь. Гарантирует кратчайший путь по числу рёбер в невзвешенном графе.

class Graph {

private:

    vector<vector<int>> adjList;

    int numVertices;



public:

    Graph(int vertices) {

        numVertices = vertices;

        adjList.resize(vertices);

    }



    void addEdge(int u, int v) {

        adjList[u].push_back(v);

        adjList[v].push_back(u); // Для неориентированного графа

    }



    void BFS(int startVertex) {

        vector<bool> visited(numVertices, false);

        queue<int> q;



        visited[startVertex] = true;

        q.push(startVertex);



        while (!q.empty()) {

            int currentVertex = q.front();

            q.pop();

            cout << "Visited " << currentVertex << " ";



            for (int neighbor : adjList[currentVertex]) {

                if (!visited[neighbor]) {

                    visited[neighbor] = true;

                    q.push(neighbor);

                }

            }

        }

    }

};

Находит кратчайшие пути от одной вершины до всех остальных во взвешенном графе с неотрицательными весами. Использует приоритетную очередь и релаксацию расстояний.

**💡**** Шпаргалка: **Работает только при неотрицательных весах. С приоритетной очередью — O((V+E)·log V).

const int INF = 1e9;



class Graph {

private:

    int V;

    vector<vector<pair<int, int>>> adjList;



public:

    Graph(int V) {

        this->V = V;

        adjList.resize(V);

    }



    void addEdge(int u, int v, int weight) {

        adjList[u].push_back({v, weight});

        adjList[v].push_back({u, weight});

    }



    void dijkstra(int startVertex) {

        vector<int> dist(V, INF);

        dist[startVertex] = 0;



        priority_queue<pair<int, int>, vector<pair<int, int>>,

                       greater<pair<int, int>>> pq;

        pq.push({0, startVertex});



        while (!pq.empty()) {

            int u = pq.top().second;

            pq.pop();

            for (auto& neighbor : adjList[u]) {

                int v = neighbor.first;

                int weight = neighbor.second;

                if (dist[u] + weight < dist[v]) {

                    dist[v] = dist[u] + weight;

                    pq.push({dist[v], v});

                }

            }

        }

        printSolution(dist);

    }



    void printSolution(const vector<int>& dist) {

        cout << "Vertex Distance from Source" << endl;

        for (int i = 0; i < V; ++i) {

            if (dist[i] == INF) cout << i << "\t\t" << "INF" << endl;

            else cout << i << "\t\t" << dist[i] << endl;

        }

    }

};

Ищет кратчайшие пути от одной вершины, допускает отрицательные веса и обнаруживает отрицательные циклы. V-1 раз релаксирует все рёбра, затем проверяет наличие отрицательного цикла.

**💡**** Шпаргалка: **Допускает отрицательные веса и находит отрицательные циклы. Сложность O(V·E).

struct Edge {

    int u, v, weight;

};



class Graph {

private:

    int V, E;

    vector<Edge> edges;



public:

    Graph(int V, int E) {

        this->V = V;

        this->E = E;

    }



    void addEdge(int u, int v, int weight) {

        edges.push_back({u, v, weight});

    }



    void BellmanFord(int startVertex) {

        vector<int> distance(V, INT_MAX);

        distance[startVertex] = 0;



        // Расслабить все ребра V-1 раз

        for (int i = 1; i <= V - 1; ++i) {

            for (int j = 0; j < E; ++j) {

                int u = edges[j].u, v = edges[j].v, weight = edges[j].weight;

                if (distance[u] != INT_MAX && distance[u] + weight < distance[v]) {

                    distance[v] = distance[u] + weight;

                }

            }

        }



        // Проверить наличие отрицательных циклов

        for (int j = 0; j < E; ++j) {

            int u = edges[j].u, v = edges[j].v, weight = edges[j].weight;

            if (distance[u] != INT_MAX && distance[u] + weight < distance[v]) {

                cout << "Graph contains negative weight cycle" << endl;

                return;

            }

        }

        printSolution(distance);

    }



    void printSolution(vector<int>& distance) {

        cout << "Vertex Distance from Source" << endl;

        for (int i = 0; i < V; ++i)

            cout << i << "\t\t" << distance[i] << endl;

    }

};

Находит кратчайшие пути между всеми парами вершин. Тремя вложенными циклами по k, i, j проверяет, не короче ли путь из i в j через промежуточную вершину k.

**💡**** Шпаргалка: **Пути между всеми парами вершин. Сложность O(V³).

const int INF = 1e9;



void floydWarshall(vector<vector<int>>& graph) {

    int V = graph.size();

    vector<vector<int>> dist = graph;



    for (int k = 0; k < V; ++k) {

        for (int i = 0; i < V; ++i) {

            for (int j = 0; j < V; ++j) {

                if (dist[i][k] < INF && dist[k][j] < INF) {

                    dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j]);

                }

            }

        }

    }



    cout << "Shortest distances between every pair of vertices:" << endl;

    for (int i = 0; i < V; ++i) {

        for (int j = 0; j < V; ++j) {

            if (dist[i][j] == INF) cout << "INF ";

            else cout << dist[i][j] << " ";

        }

        cout << endl;

    }

}

Минимальное остовное дерево (MST) соединяет все вершины с минимальной суммарной стоимостью без циклов. Прим выращивает дерево от одной вершины, добавляя самое дешёвое ребро к ещё не включённой вершине (через приоритетную очередь).

**💡**** Шпаргалка: **Наращивает дерево от вершины. С приоритетной очередью — O(E·log V). Удобен для плотных графов.

const int INF = 1e9;



class Graph {

private:

    int V;

    vector<vector<pair<int, int>>> adjList;



public:

    Graph(int V) {

        this->V = V;

        adjList.resize(V);

    }



    void addEdge(int u, int v, int weight) {

        adjList[u].push_back({v, weight});

        adjList[v].push_back({u, weight});

    }



    void primMST() {

        priority_queue<pair<int, int>, vector<pair<int, int>>,

                       greater<pair<int, int>>> pq;

        vector<int> key(V, INF);

        vector<int> parent(V, -1);

        vector<bool> inMST(V, false);



        pq.push({0, 0});

        key[0] = 0;



        while (!pq.empty()) {

            int u = pq.top().second;

            pq.pop();

            if (inMST[u]) continue;

            inMST[u] = true;



            for (auto& [v, weight] : adjList[u]) {

                if (!inMST[v] && weight < key[v]) {

                    key[v] = weight;

                    pq.push({key[v], v});

                    parent[v] = u;

                }

            }

        }

        printMST(parent);

    }



    void printMST(const vector<int>& parent) {

        cout << "Edge   Weight" << endl;

        for (int i = 1; i < V; ++i)

            cout << parent[i] << " - " << i << "    "

                 << adjList[i][parent[i]].second << endl;

    }

};

Строит MST иначе: сортирует все рёбра по весу и жадно добавляет их, пропуская те, что образуют цикл. Циклы определяются структурой Union-Find (система непересекающихся множеств) с оптимизациями по рангу и сжатию путей.

**💡**** Шпаргалка: **Сортирует рёбра и добавляет через Union-Find. Сложность O(E·log E). Удобен для разреженных графов.

using namespace std;



struct Edge {

    int u, v, weight;

    bool operator<(const Edge& other) const {

        return weight < other.weight;

    }

};



class UnionFind {

private:

    vector<int> parent, rank;

public:

    UnionFind(int n) {

        parent.resize(n);

        rank.resize(n, 0);

        for (int i = 0; i < n; ++i) parent[i] = i;

    }

    int find(int u) {

        if (u != parent[u]) parent[u] = find(parent[u]);

        return parent[u];

    }

    void unionSets(int u, int v) {

        int rootU = find(u), rootV = find(v);

        if (rootU != rootV) {

            if (rank[rootU] > rank[rootV]) parent[rootV] = rootU;

            else if (rank[rootU] < rank[rootV]) parent[rootU] = rootV;

            else { parent[rootV] = rootU; rank[rootU]++; }

        }

    }

};



class Graph {

private:

    int V;

    vector<Edge> edges;

public:

    Graph(int V) { this->V = V; }

    void addEdge(int u, int v, int weight) {

        edges.push_back({u, v, weight});

    }

    void kruskalMST() {

        sort(edges.begin(), edges.end());

        UnionFind uf(V);

        vector<Edge> mst;

        for (const auto& edge : edges) {

            if (uf.find(edge.u) != uf.find(edge.v)) {

                mst.push_back(edge);

                uf.unionSets(edge.u, edge.v);

            }

        }

        printMST(mst);

    }

    void printMST(const vector<Edge>& mst) {

        cout << "Edge   Weight" << endl;

        for (const auto& edge : mst)

            cout << edge.u << " - " << edge.v << "    " << edge.weight << endl;

    }

};
